{
  "name": "whatsapp-remote-backend",
  "version": "1.0.0",
  "description": "WhatsApp Remote Backend API",
  "main": "server.js",
  "scripts": {
    "start": "node server.js",
    "dev": "nodemon server.js"
  },
  "dependencies": {
    "whatsapp-web.js": "^1.23.0",
    "express": "^4.18.2",
    "cors": "^2.8.5",
    "qrcode": "^1.5.3",
    "socket.io": "^4.6.1",
    "multer": "^1.4.5-lts.1",
    "node-localstorage": "^2.2.1"
  },
  "devDependencies": {
