function greetingCommand() {
    const hour = new Date().getHours();
    let timeGreeting;

    if (hour < 6) timeGreeting = 'İyi geceler! 🌙';
    else if (hour < 12) timeGreeting = 'Günaydın! ☀️';
    else if (hour < 18) timeGreeting = 'İyi günler! 🌤️';
    else timeGreeting = 'İyi akşamlar! 🌆';

    return `${timeGreeting}\n\nBen ☁️ *Bulut*, senin kişisel asistanınım!\n\nSana nasıl yardımcı olabilirim?\n\nYardım için: \`!bulut yardım\``;
}

async function systemInfoCommand() {
    const hostname = os.hostname();
    const platform = os.platform();
    const arch = os.arch();
    const cpus = os.cpus().length;
    const totalMem = (os.totalmem() / 1024 / 1024 / 1024).toFixed(2);
    const freeMem = (os.freemem() / 1024 / 1024 / 1024).toFixed(2);
    const uptime = Math.floor(os.uptime() / 3600);

    return `💻 *SİSTEM BİLGİLERİ*

🖥 Bilgisayar: ${hostname}
💿 İşletim Sistemi: ${platform}
🔧 Mimari: ${arch}
⚙️ İşlemci Çekirdek: ${cpus}
💾 Toplam RAM: ${totalMem} GB
📊 Boş RAM: ${freeMem} GB
⏱ Çalışma Süresi: ${uptime} saat`;
}

async function diskInfoCommand() {
    return new Promise((resolve) => {
        exec('wmic logicaldisk get size,freespace,caption', (error, stdout) => {
            if (error) {
                resolve('❌ Disk bilgisi alınamadı');
                return;
            }

            const lines = stdout.trim().split('\n').slice(1);
            let diskInfo = '💾 *DİSK KULLANIMI*\n\n';

            lines.forEach(line => {
                const parts = line.trim().split(/\s+/);
                if (parts.length >= 3) {
                    const caption = parts[0];
                    const free = (parseInt(parts[1]) / 1024 / 1024 / 1024).toFixed(2);
                    const total = (parseInt(parts[2]) / 1024 / 1024 / 1024).toFixed(2);
                    const used = (total - free).toFixed(2);
                    const percent = ((used / total) * 100).toFixed(1);

                    diskInfo += `*${caption}*\n`;
                    diskInfo += `Toplam: ${total} GB\n`;
                    diskInfo += `Kullanılan: ${used} GB (${percent}%)\n`;
                    diskInfo += `Boş: ${free} GB\n\n`;
                }
            });

            resolve(diskInfo);
        });
    });
}

async function cpuInfoCommand() {
    const cpus = os.cpus();
    let info = '⚙️ *İŞLEMCİ BİLGİLERİ*\n\n';

    cpus.forEach((cpu, index) => {
        info += `*Çekirdek ${index + 1}:*\n`;
        info += `Model: ${cpu.model}\n`;
        info += `Hız: ${(cpu.speed / 1000).toFixed(2)} GHz\n`;
        info += `Kullanım: %{cpu.usage}%\n\n`;
    });

    return info;
}

async function memoryInfoCommand() {
    const total = (os.totalmem() / 1024 / 1024 / 1024).toFixed(2);
    const free = (os.freemem() / 1024 / 1024 / 1024).toFixed(2);
    const used = (total - free).toFixed(2);
    const percent = ((used / total) * 100).toFixed(1);

    let bar = '';
    const filled = Math.floor(percent / 5);
    for (let i = 0; i < 20; i++) {
        bar += i < filled ? '█' : '░';
    }

    return `📊 *HAFIZA KULLANIMI*

${bar} %${percent}

💾 Toplam: ${total} GB
📈 Kullanılan: ${used} GB
📉 Boş: ${free} GB`;
}

async function networkInfoCommand() {
    const interfaces = os.networkInterfaces();
    let info = '🌐 *AĞ BİLGİLERİ*\n\n';

    for (const [name, nets] of Object.entries(interfaces)) {
        for (const net of nets) {
            if (net.family === 'IPv4' && !net.internal) {
                info += `*${name}:*\n`;
                info += `IP: ${net.address}\n`;
                info += `MAC: ${net.mac}\n\n`;
            }
        }
    }

    return info;
}

async function executeCommand(cmd) {
    return new Promise((resolve) => {
        exec(cmd, { timeout: 10000 }, (error, stdout, stderr) => {
            if (error) {
                resolve(`❌ Komut Hatası:\n\`\`\`\n${error.message}\n\`\`\``);
                return;
            }

            const output = stdout || stderr;
            if (output.length > 4000) {
                resolve(`📋 *Komut Çıktısı:* (kısaltıldı)\n\`\`\`\n${output.substring(0, 3990)}...\n\`\`\``);
            } else {
                resolve(`📋 *Komut Çıktısı:*\n\`\`\`\n${output}\n\`\`\``);
            }
        });
    });
}

async function fileCommand(args) {
    if (args.length < 2) {
        return '❌ Kullanım: !bulut dosya [dosya_adı] [içerik]';
    }

    const fileName = args[0];
    const content = args.slice(1).join(' ');
    const filePath = path.join(process.cwd(), fileName);

    try {
        fs.writeFileSync(filePath, content);
        return `✅ Dosya oluşturuldu:\n📁 ${filePath}`;
    } catch (error) {
        return `❌ Dosya oluşturulamadı: ${error.message}`;
    }
}

async function folderCommand(args) {
    if (args.length < 1) {
        return '❌ Kullanım: !bulut klasör [klasör_adı]';
    }

    const folderName = args[0];
    const folderPath = path.join(process.cwd(), folderName);

    try {
        fs.mkdirSync(folderPath, { recursive: true });
        return `✅ Klasör oluşturuldu:\n📁 ${folderPath}`;
    } catch (error) {
        return `❌ Klasör oluşturulamadı: ${error.message}`;
    }
}

async function listDirectoryCommand(dir) {
    return new Promise((resolve) => {
        const dirPath = path.resolve(dir);

        fs.readdir(dirPath, (error, files) => {
            if (error) {
                resolve(`❌ Klasör okunamadı: ${error.message}`);
                return;
            }

            let output = `📁 *${dirPath}*\n\n`;

            if (files.length === 0) {
                output += '(Boş klasör)';
            } else {
                files.forEach((file, index) => {
                    const isDir = fs.statSync(path.join(dirPath, file)).isDirectory();
                    output += `${index + 1}. ${isDir ? '📁' : '📄'} ${file}\n`;
                });
            }

            resolve(output);
        });
    });
}

async function readFileCommand(filePath) {
    if (!filePath) {
        return '❌ Kullanım: !bulut oku [dosya_yolu]';
    }

    try {
        const fullPath = path.resolve(filePath);
        const content = fs.readFileSync(fullPath, 'utf8');

        if (content.length > 4000) {
            return `📄 *${filePath}*\n\n${content.substring(0, 3990)}...\n\n(Dosya çok uzun)`;
        }

        return `📄 *${filePath}*\n\n${content}`;
    } catch (error) {
        return `❌ Dosya okunamadı: ${error.message}`;
    }
}

async function weatherCommand(city) {
    if (!city) {
        return '❌ Kullanım: !bulut hava [şehir]';
    }

    return `🌤️ *HAVA DURUMU - ${city.toUpperCase()}*\n\nHava durumu servisi yapılandırılmalı.\nAPI anahtarı ekleyerek tam bilgi alabilirsin.`;
}

async function calculateCommand(expression) {
    if (!expression) {
        return '❌ Kullanım: !bulut hesapla [işlem] (ör: 2+2)';
    }

    try {
        // Safe evaluation
        const sanitized = expression.replace(/[^0-9+\-*/().%\s]/g, '');
        const result = eval(sanitized);

        return `🧮 *HESAPLAMA*\n\n${expression} = *${result}*`;
    } catch (error) {
        return `❌ Hesaplama hatası: Geçersiz ifade`;
    }
}

async function noteCommand(note) {
    if (!note) {
        return '❌ Kullanım: !bulut not [notunuz]';
    }

    const notesDir = path.join(process.cwd(), 'notes');
    if (!fs.existsSync(notesDir)) {
        fs.mkdirSync(notesDir);
    }

    const notesFile = path.join(notesDir, 'notes.json');
    let notes = [];

    if (fs.existsSync(notesFile)) {
        notes = JSON.parse(fs.readFileSync(notesFile, 'utf8'));
    }

    notes.push({
        id: notes.length + 1,
        text: note,
        date: new Date().toLocaleString('tr-TR')
    });

    fs.writeFileSync(notesFile, JSON.stringify(notes, null, 2));

    return `✅ *NOT KAYDEDİLDİ*\n\n📝 ${note}\n📅 ${new Date().toLocaleString('tr-TR')}`;
}

async function listNotesCommand(userId) {
    const notesFile = path.join(process.cwd(), 'notes', 'notes.json');

    if (!fs.existsSync(notesFile)) {
        return '📝 Henüz not yok.\n\nNot eklemek için: !bulut not [not]';
    }

    const notes = JSON.parse(fs.readFileSync(notesFile, 'utf8'));

    if (notes.length === 0) {
        return '📝 Henüz not yok.';
    }

    let output = '📝 *NOTLARINIZ*\n\n';
    notes.forEach((note, index) => {
        output += `*${index + 1}.* ${note.text}\n`;
        output += `   📅 ${note.date}\n\n`;
    });

    return output;
}

async function deleteNoteCommand(noteId) {
    if (!noteId) {
        return '❌ Kullanım: !bulut sil [not_numarası]';
    }

    const notesFile = path.join(process.cwd(), 'notes', 'notes.json');

    if (!fs.existsSync(notesFile)) {
        return '❌ Not bulunamadı';
    }

    let notes = JSON.parse(fs.readFileSync(notesFile, 'utf8'));
    const id = parseInt(noteId) - 1;

    if (id < 0 || id >= notes.length) {
        return '❌ Geçersiz not numarası';
    }

    const deleted = notes.splice(id, 1)[0];
    fs.writeFileSync(notesFile, JSON.stringify(notes, null, 2));

    return `✅ *NOT SİLİNDİ*\n\n📝 ${deleted.text}`;
}

async function timerCommand(args) {
    if (!args[0]) {
        return '❌ Kullanım: !bulut zamanlayıcı [saniye]';
    }

    const seconds = parseInt(args[0]);

    if (isNaN(seconds) || seconds < 1 || seconds > 3600) {
        return '❌ Geçersiz süre (1-3600 saniye)';
    }

    setTimeout(() => {
        // This would need the msg object to send a message
        console.log(`⏰ Zamanlayıcı doldu: ${seconds} saniye`);
    }, seconds * 1000);

    return `⏰ *ZAMANLAYICI KURULDU*\n\n⏱ ${seconds} saniye sonra haber vereceğim!`;
}

async function reminderCommand(args) {
    if (args.length < 2) {
        return '❌ Kullanım: !bulut hatırlat [saniye] [hatırlatma]';
    }

    const seconds = parseInt(args[0]);
    const reminder = args.slice(1).join(' ');

    if (isNaN(seconds)) {
        return '❌ Geçersiz süre';
    }

    setTimeout(() => {
        console.log(`🔔 Hatırlatma: ${reminder}`);
    }, seconds * 1000);

    return `🔔 *HATIRLATICI KURULDU*\n\n⏱ ${seconds} saniye içinde: ${reminder}`;
}

async function translateCommand(args) {
    if (args.length < 2) {
        return '❌ Kullanım: !bulut çevir [dil] [metin]';
    }

    return `🌐 *ÇEVİRİ*\n\nÇeviri servisi yapılandırılmalı.`;
}

async function qrCodeCommand(text) {
    if (!text) {
        return '❌ Kullanım: !bulut qr [metin/link]';
    }

    return `📱 QR Kod oluşturuldu:\n\n${text}\n\n(Web arayüzünde görüntüleyebilirsiniz)`;
}

async function sendWhatsAppCommand(args) {
    if (args.length < 2) {
        return '❌ Kullanım: !bulut mesaj [numara] [mesaj]';
    }

    const number = args[0];
    const message = args.slice(1).join(' ');

    return `📱 Mesaj gönderilecek:\n\n📞 ${number}\n💬 ${message}\n\n(Onay için komutu tamamlayın)`;
}

async function listContactsCommand(client) {
    try {
        const chats = await client.getChats();
        const contacts = chats.slice(0, 20);

        let output = '👥 *KİŞİLER* (ilk 20)\n\n';
        contacts.forEach((chat, index) => {
            output += `${index + 1}. ${chat.name || chat.id.user}\n`;
        });

        return output;
    } catch (error) {
        return `❌ Kişiler alınamadı: ${error.message}`;
    }
}

async function listChatsCommand(client) {
    try {
        const chats = await client.getChats();

        let output = `💬 *SOHBETLER* (${chats.length})\n\n`;
        chats.slice(0, 15).forEach((chat, index) => {
            const name = chat.name || chat.id.user;
            const lastMsg = chat.lastMessage?.body?.substring(0, 30) || '-';
            output += `${index + 1}. ${name}\n   💬 ${lastMsg}\n\n`;
        });

        return output;
    } catch (error) {
        return `❌ Sohbetler alınamadı: ${error.message}`;
    }
}

async function cleanTempCommand() {
    return new Promise((resolve) => {
        exec('powershell -Command "Remove-Item -Path \'$env:TEMP\\*\' -Recurse -Force -ErrorAction SilentlyContinue"', (error, stdout) => {
            if (error) {
                resolve('❌ Temizleme hatası');
                return;
            }

            resolve('✅ *GEÇİCİ DOSYALAR TEMİZLENDİ*\n\nSistem daha hızlı çalışmalı!');
        });
    });
}

async function updateSystemCommand() {
    return '🔄 *SİSTEM GÜNCELLEME*\n\nWindows Update\'i manuel olarak çalıştırmanız gerekiyor.\n\nAyarlar > Windows Update > Güncellemeleri Denetle';
}

async function restartCommand() {
    return '⚠️ *YENİDEN BAŞLATMA*\n\nBilgisayarı yeniden başlatmak istediğine emin misin?\n\nKomut: !bulut yeniden onay';
}

async function whoamiCommand() {
    return new Promise((resolve) => {
        exec('whoami', (error, stdout) => {
            if (error) {
                resolve('❌ Kullanıcı bilgisi alınamadı');
                return;
            }

            resolve(`👤 *KULLANICI*\n\n${stdout.trim()}`);
        });
    });
}

async function uptimeCommand() {
    const uptime = os.uptime();
    const days = Math.floor(uptime / 86400);
    const hours = Math.floor((uptime % 86400) / 3600);
    const minutes = Math.floor((uptime % 3600) / 60);

    return `⏱ *ÇALIŞMA SÜRESİ*\n\n${days} gün, ${hours} saat, ${minutes} dakika`;
}

async function processListCommand() {
    return new Promise((resolve) => {
        exec('tasklist /fo csv', (error, stdout) => {
            if (error) {
                resolve('❌ İşlem listesi alınamadı');
                return;
            }

            const processes = stdout.trim().split('\n').slice(1, 16);
            let output = '🔄 *İŞLEMLER* (ilk 15)\n\n';

            processes.forEach((proc, index) => {
                const parts = proc.split(',');
                const name = parts[0].replace(/"/g, '');
                const mem = parts[4] ? parts[4].replace(/"/g, '') : '-';
                output += `${index + 1}. ${name} - ${mem}\n`;
            });

            resolve(output);
        });
    });
}

function cloudEmojiCommand() {
    return '☁️';
}

function naturalLanguageResponse(input) {
    const lower = input.toLowerCase();

    // Greeting responses
    if (lower.includes('nasılsın') || lower.includes('naber')) {
        return `☁️ Teşekkürler, iyiyim! Sana nasıl yardımcı olabilirim?\n\nKomutlar için: \`!bulut yardım\``;
    }

    if (lower.includes('teşekkür') || lower.includes('sağol')) {
        return `☁️ Rica ederim! 😊 Başka bir şey var mı?`;
    }

    if (lower.includes('kimsin') || lower.includes('sen kimsin')) {
        return `☁️ Ben *Bulut*! Senin kişisel AI asistanınım.\n\nSistemi yönetebilir, dosyalarla çalışabilir, hesaplamalar yapabilir ve çok daha fazlasını yapabilirim!\n\nYardım için: \`!bulut yardım\``;
    }

    if (lower.includes('ne yapabilirsin')) {
        return `☁️ *YAPABİLECEKLERİM:*\n\n✅ Sistem bilgisi\n✅ Dosya yönetimi\n✅ Komut çalıştırma\n✅ Hesaplamalar\n✅ Not alma\n✅ WhatsApp yönetimi\n✅ Hava durumu\n✅ Ve daha fazlası!\n\nTam liste: \`!bulut yardım\``;
    }

    // Default response
    return `☁️ Mesajını aldım ama tam olarak anlayamadım.\n\nSana şu konularda yardımcı olabilirim:\n\n• \`!bulut yardım\` - Komut listesi\n• \`!bulut sistem\` - Sistem bilgisi\n• \`!bulut hesapla 2+2\` - Hesaplama\n• \`!bulut not notum\` - Not kaydet\n\nBaşka bir şey denemek ister misin?`;
}

module.exports = {
    processCommand,
    BOT_NAME,
    BOT_VERSION
};

