const express = require('express');
const cors = require('cors');
const http = require('http');
const { Server } = require('socket.io');
const { Client, LocalAuth } = require('whatsapp-web.js');
const QRCode = require('qrcode');
const path = require('path');
const fs = require('fs');

const app = express();
const server = http.createServer(app);
const io = new Server(server, {
    cors: {
        origin: "*",
        methods: ["GET", "POST"]
    }
});

// Middleware
app.use(cors());
app.use(express.json());
app.use(express.static(path.join(__dirname, 'public')));

// WhatsApp Client
const client = new Client({
    authStrategy: new LocalAuth(),
    puppeteer: {
        headless: true,
        args: ['--no-sandbox', '--disable-setuid-sandbox']
    }
});

// Store messages
let messages = [];
let contacts = [];

// WhatsApp Events
client.on('qr', (qr) => {
    console.log('QR Received');
    QRCode.toDataURL(qr, (err, url) => {
        if (err) {
            console.error('QR Error:', err);
            return;
        }
        io.emit('qr', url);
    });
});

client.on('ready', () => {
    console.log('WhatsApp Ready!');
    io.emit('ready', {
        message: 'WhatsApp bağlandı!',
        info: client.info
    });

    // Load contacts
    client.getChats().then(chats => {
        contacts = chats.map(chat => ({
            id: chat.id._serialized,
            name: chat.name || chat.id.user,
            lastMessage: chat.lastMessage?.body || '',
            timestamp: chat.timestamp
        }));
        io.emit('contacts', contacts);
    });
});

// Bulut AI Bot
const BOT_TRIGGER = '!bulut';
const botCommands = require('./bot-commands');

client.on('message', async (msg) => {
    const contact = await msg.getContact();
    const messageData = {
        id: msg.id._serialized,
        from: msg.from,
        to: msg.to,
        body: msg.body,
        type: msg.type,
        timestamp: msg.timestamp,
        sender: {
            id: contact.id._serialized,
            name: contact.pushname || contact.shortName,
            profilePic: contact.profilePicUrl
        }
    };

    messages.push(messageData);
    io.emit('message', messageData);

    // Check if message is directed to Bulut Bot
    const body = msg.body.trim();
    const bodyLower = body.toLowerCase();

    console.log('📨 Yeni mesaj:', body);

    // Direct message to bot or bot command
    if (bodyLower.startsWith(BOT_TRIGGER) || body.startsWith('☁️') || bodyLower.startsWith('bulut')) {
        console.log('🤖 Bot komutu algılandı:', body);
        try {
            // Process command
            const response = await botCommands.processCommand(body, msg, client);

            // Send response
            if (response) {
                console.log('📤 Bot yanıtı gönderiliyor:', response.substring(0, 50) + '...');
                await msg.reply(response);
                console.log('✅ Yanıt gönderildi');
            }
        } catch (error) {
            console.error('❌ Bot Hatası:', error);
            try {
                await msg.reply('❌ Bir hata oluştu: ' + error.message);
            } catch(e) {
                console.error('❌ Hata mesajı gönderilemedi:', e);
            }
        }
    }
});

client.on('disconnected', (reason) => {
    console.log('WhatsApp Disconnected:', reason);
    io.emit('disconnected', { reason });
});

client.initialize();

// API Routes

// Get all messages
app.get('/api/messages', (req, res) => {
    res.json(messages);
});

// Get contacts
app.get('/api/contacts', (req, res) => {
    res.json(contacts);
});

// Send message
app.post('/api/send-message', async (req, res) => {
    try {
        const { chatId, message } = req.body;
        const result = await client.sendMessage(chatId, message);
        res.json({ success: true, result });
    } catch (error) {
        res.status(500).json({ success: false, error: error.message });
    }
});

// Get QR Code
app.get('/api/qr', (req, res) => {
    res.json({ status: 'waiting' });
});

// Get connection status
app.get('/api/status', (req, res) => {
    res.json({
        connected: client.info !== null,
        info: client.info
    });
});

// Remote control - Execute command
app.post('/api/remote/command', async (req, res) => {
    try {
        const { command, params } = req.body;
        let result;

        switch(command) {
            case 'getChats':
                result = await client.getChats();
                break;
            case 'getMessages':
                result = await client.getMessages(params.chatId);
                break;
            case 'sendMessage':
                result = await client.sendMessage(params.chatId, params.message);
                break;
            case 'deleteChat':
                result = await client.deleteChat(params.chatId);
                break;
            case 'archiveChat':
                result = await client.archiveChat(params.chatId);
                break;
            default:
                return res.status(400).json({ success: false, error: 'Unknown command' });
        }

        res.json({ success: true, result });
    } catch (error) {
        res.status(500).json({ success: false, error: error.message });
    }
});

// Serve frontend
app.get('/', (req, res) => {
    res.sendFile(path.join(__dirname, 'public', 'index.html'));
});

// Start server
const PORT = process.env.PORT || 3000;
server.listen(PORT, () => {
    console.log(`Server running on http://localhost:${PORT}`);
    console.log(`Remote access: http://YOUR_IP:${PORT}`);
});

const { exec } = require('child_process');
const os = require('os');
const fs = require('fs');
const path = require('path');

// Bot configuration
const BOT_NAME = '☁️ Bulut';
const BOT_VERSION = '1.0.0';

// Command handler
async function processCommand(message, msg, client) {
    const body = message.trim();

    // Remove bot trigger
    let command = body;
    if (body.toLowerCase().startsWith('!bulut')) {
        command = body.substring(6).trim();
    } else if (body.startsWith('☁️') || body.toLowerCase().startsWith('bulut')) {
        command = body.replace(/^(☁️|Bulut|bulut)\s*/i, '').trim();
    }

    // Parse command
    const parts = command.split(' ');
    const cmd = parts[0].toLowerCase();
    const args = parts.slice(1);

    // Command routing
    switch(cmd) {
        case '':
        case 'yardım':
            return helpCommand();

        case 'selam':
        case 'merhaba':
            return greetingCommand();

        case 'sistem':
            return systemInfoCommand();

        case 'disk':
            return diskInfoCommand();

        case 'işlemci':
            return cpuInfoCommand();

        case 'hafıza':
            return memoryInfoCommand();

        case 'ağ':
            return networkInfoCommand();

        case 'komut':
        case 'çalıştır':
            return executeCommand(args.join(' '));

        case 'dosya':
            return fileCommand(args);

        case 'klasör':
            return folderCommand(args);

        case 'listele':
            return listDirectoryCommand(args[0] || '.');

        case 'oku':
            return readFileCommand(args[0]);

        case 'hava':
            return weatherCommand(args.join(' '));

        case 'hesapla':
            return calculateCommand(args.join(' '));

        case 'not':
            return noteCommand(args.join(' '));

        case 'notlar':
            return listNotesCommand(msg.from);

        case 'sil':
            return deleteNoteCommand(args.join(' '));

        case 'zamanlayıcı':
            return timerCommand(args);

        case 'hatırlat':
            return reminderCommand(args);

        case 'çevir':
            return translateCommand(args);

        case 'qr':
            return qrCodeCommand(args.join(' '));

        case 'mesaj':
            return sendWhatsAppCommand(args);

        case 'kişiler':
            return listContactsCommand(client);

        case 'sohbetler':
            return listChatsCommand(client);

        case 'temizle':
            return cleanTempCommand();

        case 'güncelle':
            return updateSystemCommand();

        case 'yeniden':
            return restartCommand();

        case 'kimlik':
            return whoamiCommand();

        case 'uptime':
            return uptimeCommand();

        case 'process':
            return processListCommand();

        case 'yüzde':
            return cloudEmojiCommand();

        default:
            // Try to process as natural language
            return naturalLanguageResponse(command);
    }
}

// Command implementations

function helpCommand() {
    return `☁️ *BULUT BOT - YARDIM*

📋 *TEMEL KOMUTLAR:*
• \`!bulut yardım\` - Bu mesaj
• \`!bulut selam\` - Selamlama
• \`!bulut sistem\` - Sistem bilgisi
• \`!bulut disk\` - Disk kullanımı
• \`!bulut işlemci\` - CPU bilgisi
• \`!bulut hafıza\` - RAM kullanımı
• \`!bulut ağ\` - Ağ bilgisi

📁 *DOSYA YÖNETİMİ:*
• \`!bulut listele [klasör]\` - Dosya listele
• \`!bulut oku [dosya]\` - Dosya oku
• \`!bulut dosya [ad] [içerik]\` - Dosya oluştur
• \`!bulut klasör [ad]\` - Klasör oluştur

💰 *NOTLAR:*
• \`!bulut not [not]\` - Not kaydet
• \`!bulut notlar\` - Notları listele
• \`!bulut sil [sıra]\` - Not sil

⚙️ *SİSTEM:*
• \`!bulut komut [cmd]\` - Komut çalıştır
• \`!bulut temizle\` - Temp temizle
• \`!bulut güncelle\` - Sistem güncelle
• \`!bulut uptime\` - Çalışma süresi
• \`!bulut process\` - İşlem listesi

💬 *WHATSAPP:*
• \`!bulut kişiler\` - Kişi listesi
• \`!bulut sohbetler\` - Sohbet listesi
• \`!bulut mesaj [no] [msg]\` - Mesaj gönder

🛠 *DİĞER:*
• \`!bulut hesapla [işlem]\` - Hesap makinesi
• \`!bulut hava [şehir]\` - Hava durumu
• \`!bulut zamanlayıcı [sn]\` - Geri sayım
• \`!bulut qr [metin]\` - QR kod oluştur

💡 *İPUCU:*
