async function calculateCommand(expression) {
    if (!expression) {
        return '❌ Kullanım: !bulut hesapla [işlem] (ör: 2+2)';
    }

    try {
        // Safe evaluation
        const sanitized = expression.replace(/[^0-9+\-*/().%\s]/g, '');
        const result = eval(sanitized);

        return `🧮 *HESAPLAMA*\n\n${expression} = *${result}*`;
    } catch (error) {
        return `❌ Hesaplama hatası: Geçersiz ifade`;
    }
