async function noteCommand(note) {
    if (!note) {
        return '❌ Kullanım: !bulut not [notunuz]';
    }

    const notesDir = path.join(process.cwd(), 'notes');
    if (!fs.existsSync(notesDir)) {
        fs.mkdirSync(notesDir);
    }

    const notesFile = path.join(notesDir, 'notes.json');
    let notes = [];

    if (fs.existsSync(notesFile)) {
        notes = JSON.parse(fs.readFileSync(notesFile, 'utf8'));
    }

    notes.push({
        id: notes.length + 1,
        text: note,
        date: new Date().toLocaleString('tr-TR')
    });

    fs.writeFileSync(notesFile, JSON.stringify(notes, null, 2));

    return `✅ *NOT KAYDEDİLDİ*\n\n📝 ${note}\n📅 ${new Date().toLocaleString('tr-TR')}`;
}

async function listNotesCommand(userId) {
    const notesFile = path.join(process.cwd(), 'notes', 'notes.json');

    if (!fs.existsSync(notesFile)) {
        return '📝 Henüz not yok.\n\nNot eklemek için: !bulut not [not]';
    }

    const notes = JSON.parse(fs.readFileSync(notesFile, 'utf8'));

    if (notes.length === 0) {
        return '📝 Henüz not yok.';
    }

    let output = '📝 *NOTLARINIZ*\n\n';
    notes.forEach((note, index) => {
        output += `*${index + 1}.* ${note.text}\n`;
        output += `   📅 ${note.date}\n\n`;
    });

    return output;
}

async function deleteNoteCommand(noteId) {
    if (!noteId) {
        return '❌ Kullanım: !bulut sil [not_numarası]';
    }

    const notesFile = path.join(process.cwd(), 'notes', 'notes.json');

    if (!fs.existsSync(notesFile)) {
        return '❌ Not bulunamadı';
    }

    let notes = JSON.parse(fs.readFileSync(notesFile, 'utf8'));
    const id = parseInt(noteId) - 1;

    if (id < 0 || id >= notes.length) {
        return '❌ Geçersiz not numarası';
    }

    const deleted = notes.splice(id, 1)[0];
    fs.writeFileSync(notesFile, JSON.stringify(notes, null, 2));

    return `✅ *NOT SİLİNDİ*\n\n📝 ${deleted.text}`;
}

