const express = require('express');
const cors = require('cors');
const http = require('http');
const { Server } = require('socket.io');
const { Client, LocalAuth } = require('whatsapp-web.js');
const QRCode = require('qrcode');
const path = require('path');
const fs = require('fs');

const app = express();
const server = http.createServer(app);
const io = new Server(server, {
    cors: {
        origin: "*",
        methods: ["GET", "POST"]
    }
});

// Middleware
app.use(cors());
app.use(express.json());
app.use(express.static(path.join(__dirname, 'public')));

// WhatsApp Client
const client = new Client({
    authStrategy: new LocalAuth(),
    puppeteer: {
        headless: true,
        args: ['--no-sandbox', '--disable-setuid-sandbox']
    }
});

// Store messages
let messages = [];
let contacts = [];

// WhatsApp Events
client.on('qr', (qr) => {
    console.log('QR Received');
    QRCode.toDataURL(qr, (err, url) => {
        if (err) {
            console.error('QR Error:', err);
            return;
        }
        io.emit('qr', url);
    });
});

client.on('ready', () => {
    console.log('WhatsApp Ready!');
    io.emit('ready', {
        message: 'WhatsApp bağlandı!',
        info: client.info
    });

    // Load contacts
    client.getChats().then(chats => {
        contacts = chats.map(chat => ({
            id: chat.id._serialized,
            name: chat.name || chat.id.user,
            lastMessage: chat.lastMessage?.body || '',
            timestamp: chat.timestamp
        }));
        io.emit('contacts', contacts);
    });
});

// Bulut AI Bot
const BOT_TRIGGER = '!bulut';
const BOT_TRIGGER_LOWER = '!bulut';
const botCommands = require('./bot-commands');

// DEBUG MODE - Tüm mesajleri logla
const DEBUG_MODE = true;

client.on('message', async (msg) => {
    console.log('\n' + '='.repeat(60));
    console.log('🔔 YENI MESAJ EVENT\'I TETIKLENDI!');
    console.log('='.repeat(60));

    try {
        // Log raw message object
        if (DEBUG_MODE) {
            console.log('📦 RAW MSG OBJECT:', JSON.stringify({
                id: msg.id?._serialized,
                from: msg.from,
                to: msg.to,
                body: msg.body,
                type: msg.type,
                hasMedia: msg.hasMedia,
                timestamp: msg.timestamp
            }, null, 2));
        }

        const contact = await msg.getContact();
        const messageData = {
            id: msg.id._serialized,
            from: msg.from,
            to: msg.to,
            body: msg.body,
            type: msg.type,
            timestamp: msg.timestamp,
            sender: {
                id: contact.id._serialized,
                name: contact.pushname || contact.shortName,
                profilePic: contact.profilePicUrl
            }
        };

        console.log('✅ Message data extracted:', messageData);

        messages.push(messageData);
        io.emit('message', messageData);

        // Check if message is directed to Bulut Bot
        const body = msg.body ? msg.body.trim() : '';
        const bodyLower = body.toLowerCase();

        console.log('\n📨 Mesaj icerigi:', body);
        console.log('🔍 Mesaj kaynağı:', msg.from);
        console.log('🔍 Mesaj tipi:', msg.type);
        console.log('🔍 Mesaj uzunluğu:', body.length, 'karakter');

        // Direct message to bot or bot command
        // Normalize Turkish characters for comparison
        const normalizedBodyLower = bodyLower
            .replace(/i̇/g, 'i')  // Remove dot from İ
            .replace(/ı/g, 'i')   // ı -> i
            .replace(/ş/g, 's')   // ş -> s
            .replace(/ç/g, 'c')   // ç -> c
            .replace(/ğ/g, 'g')   // ğ -> g
            .replace(/ü/g, 'u')   // ü -> u
            .replace(/ö/g, 'o');  // ö -> o

        console.log('🔍 Normalized mesaj:', normalizedBodyLower);

        const isBotTrigger = 
            normalizedBodyLower.startsWith(BOT_TRIGGER_LOWER) || 
            body.startsWith('☁️') || 
            body.startsWith('🌥️') ||
            normalizedBodyLower.startsWith('bulut') ||
            normalizedBodyLower.startsWith('bulut ');

        console.log('\n🎯 Bot trigger kontrolü:');
        console.log('  - !bulut ile başlıyor mu?', normalizedBodyLower.startsWith(BOT_TRIGGER_LOWER));
        console.log('  - ☁️ ile başlıyor mu?', body.startsWith('☁️'));
        console.log('  - 🌥️ ile başlıyor mu?', body.startsWith('🌥️'));
        console.log('  - bulut ile başlıyor mu?', normalizedBodyLower.startsWith('bulut'));
        console.log('  - SONUÇ:', isBotTrigger ? '✅ EVET - Bot komutu!' : '❌ HAYIR - Atlanıyor');

        if (isBotTrigger) {
            console.log('\n🤖 Bot komutu algılandı:', body);
            try {
                // Process command - pass full message object and body
                console.log('⚙️ processCommand çağrılıyor...');
                const response = await botCommands.processCommand(body, msg, client);
                console.log('⚙️ processCommand döndü:', response ? response.substring(0, 50) + '...' : 'NULL/YANIT YOK');

                // Send response
                if (response) {
                    console.log('📤 Bot yanıtı gönderiliyor...');
                    console.log('📤 Yanıt içeriği (ilk 100 karakter):', response.substring(0, 100));

                    // Use chat.sendMessage instead of msg.reply for better compatibility
                    console.log('💬 getChat() çağrılıyor...');
                    const chat = await msg.getChat();
                    console.log('💬 Chat object alındı:', chat.id?._serialized);

                    console.log('💬 sendMessage() çağrılıyor...');
                    await chat.sendMessage(response);

                    console.log('✅ Yanıt gönderildi!');
                } else {
                    console.log('⚠️ Bot yanıt üretmedi (response null/undefined)');
                    console.log('⚠️ processCommand fonksiyonunu kontrol et!');
                }
            } catch (error) {
                console.error('\n❌ Bot Hatası:', error);
                console.error('❌ Hata detayı:', error.stack);
                try {
                    const chat = await msg.getChat();
                    await chat.sendMessage('❌ Bir hata oluştu: ' + error.message);
                } catch(e) {
                    console.error('❌ Hata mesajı gönderilemedi:', e);
                }
            }
        } else {
            console.log('\n⏭️ Bot komutu değil, atlanıyor');
            console.log('💡 İpucu: Mesaj "!bulut", "bulut", veya "☁️" ile başlamalı');
        }
    } catch (error) {
        console.error('\n❌ Message handler hatası:', error);
        console.error('❌ Hata detayı:', error.stack);
    }

    console.log('='.repeat(60));
    console.log('🏁 MESAJ ISLEME TAMAMLANDI\n');
});

client.on('disconnected', (reason) => {
    console.log('WhatsApp Disconnected:', reason);
    io.emit('disconnected', { reason });
});

