const { exec } = require('child_process');
const os = require('os');
const fs = require('fs');
const path = require('path');

// Bot configuration
const BOT_NAME = '☁️ Bulut';
const BOT_VERSION = '1.0.0';

// Command handler
async function processCommand(message, msg, client) {
    const body = message.trim();

    // Remove bot trigger and normalize
    let command = body;
    if (body.toLowerCase().startsWith('!bulut')) {
        command = body.substring(6).trim();
    } else if (body.startsWith('☁️') || body.startsWith('🌥️')) {
        command = body.replace(/^(☁️|🌥️)\s*/i, '').trim();
    } else if (body.toLowerCase().startsWith('bulut')) {
        command = body.replace(/^(bulut|Bulut|BULUT)\s*/i, '').trim();
    }

    // Normalize Turkish characters in command for switch-case compatibility
    const normalizedCommand = command.toLowerCase()
        .replace(/i̇/g, 'i')  // Remove dot from İ
        .replace(/ı/g, 'i')   // ı -> i
        .replace(/ş/g, 's')   // ş -> s
        .replace(/ç/g, 'c')   // ç -> c
        .replace(/ğ/g, 'g')   // ğ -> g
        .replace(/ü/g, 'u')   // ü -> u
        .replace(/ö/g, 'o');  // ö -> o

    // Parse command
    const parts = normalizedCommand.split(' ');
    const cmd = parts[0].toLowerCase();
    const args = parts.slice(1);

    // Command routing - all using ASCII normalized commands
    switch(cmd) {
        case '':
        case 'yardim':          // yardım
        case 'help':
